import{c as s,O as a,i as n,m as i}from"./chunks/framework.BWIk71Uc.js";const g=JSON.parse('{"title":"Review Outline","description":"","frontmatter":{},"headers":[],"relativePath":"en/notes/spring/spring-cloud-alibaba/review.md","filePath":"en/notes/spring/spring-cloud-alibaba/review.md","lastUpdated":1779889564000}'),t={name:"en/notes/spring/spring-cloud-alibaba/review.md"};function l(p,e,r,o,c,d){return a(),n("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1779889564000"},[...e[0]||(e[0]=[i(`<h1 id="review-outline" tabindex="-1">Review Outline <a class="header-anchor" href="#review-outline" aria-label="Permalink to “Review Outline”">​</a></h1><h2 id="_11-1-nacos-discovery-review-points" tabindex="-1">11.1 Nacos Discovery Review Points <a class="header-anchor" href="#_11-1-nacos-discovery-review-points" aria-label="Permalink to “11.1 Nacos Discovery Review Points”">​</a></h2><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Nacos Discovery is a service registration and discovery component.</span></span>
<span class="line"><span>Services register with Nacos upon startup.</span></span>
<span class="line"><span>Consumers discover service instances via the service name.</span></span>
<span class="line"><span>Service instances can be deployed with multiple replicas.</span></span>
<span class="line"><span>Load balancing selects one instance for invocation.</span></span>
<span class="line"><span>Namespace and group can be used for environment and group isolation.</span></span></code></pre></div><hr><h2 id="_11-2-nacos-config-review-points" tabindex="-1">11.2 Nacos Config Review Points <a class="header-anchor" href="#_11-2-nacos-config-review-points" aria-label="Permalink to “11.2 Nacos Config Review Points”">​</a></h2><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Nacos Config is a configuration center.</span></span>
<span class="line"><span>Configuration can be moved from local application.yml to Nacos.</span></span>
<span class="line"><span>DataId is typically service-name-environment.yml.</span></span>
<span class="line"><span>Spring Boot 2.4+ recommends using spring.config.import.</span></span>
<span class="line"><span>@RefreshScope enables dynamic configuration refresh.</span></span>
<span class="line"><span>Shared configurations are suitable for common settings.</span></span></code></pre></div><hr><h2 id="_11-3-openfeign-review-points" tabindex="-1">11.3 OpenFeign Review Points <a class="header-anchor" href="#_11-3-openfeign-review-points" aria-label="Permalink to “11.3 OpenFeign Review Points”">​</a></h2><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>OpenFeign is a declarative HTTP client.</span></span>
<span class="line"><span>Remote services are declared via @FeignClient.</span></span>
<span class="line"><span>Enable scanning via @EnableFeignClients.</span></span>
<span class="line"><span>Feign generates proxy objects under the hood.</span></span>
<span class="line"><span>HTTP requests are initiated when interface methods are called.</span></span>
<span class="line"><span>Feign can integrate with Nacos for service discovery.</span></span>
<span class="line"><span>Feign can integrate with Sentinel for fallback.</span></span></code></pre></div><hr><h2 id="_11-4-sentinel-review-points" tabindex="-1">11.4 Sentinel Review Points <a class="header-anchor" href="#_11-4-sentinel-review-points" aria-label="Permalink to “11.4 Sentinel Review Points”">​</a></h2><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Sentinel is a traffic governance component.</span></span>
<span class="line"><span>Core concepts are resources and rules.</span></span>
<span class="line"><span>Resources can be interfaces, methods, or Feign calls.</span></span>
<span class="line"><span>Rules include flow control, circuit breaking, hotspot, system, and authorization.</span></span>
<span class="line"><span>QPS flow control limits the maximum requests per second.</span></span>
<span class="line"><span>Circuit breaking can be triggered by slow call ratio, exception ratio, or exception count.</span></span>
<span class="line"><span>Sentinel Dashboard is lazy-loaded by default; interfaces must be accessed first.</span></span>
<span class="line"><span>Rules manually configured in the Dashboard are not persisted by default.</span></span></code></pre></div><hr><h2 id="_11-5-gateway-review-points" tabindex="-1">11.5 Gateway Review Points <a class="header-anchor" href="#_11-5-gateway-review-points" aria-label="Permalink to “11.5 Gateway Review Points”">​</a></h2><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Gateway is the unified entry point for microservices.</span></span>
<span class="line"><span>Core components are Route, Predicate, and Filter.</span></span>
<span class="line"><span>Route defines routing rules.</span></span>
<span class="line"><span>Predicate determines if a request matches.</span></span>
<span class="line"><span>Filter can modify requests and responses.</span></span>
<span class="line"><span>lb://service-name indicates load-balanced calls via the registry.</span></span>
<span class="line"><span>Spring Cloud 2025 recommends using the new gateway-server-webflux starter and new property prefixes.</span></span>
<span class="line"><span>Gateway is a WebFlux reactive application; do not mix with Servlet Web.</span></span></code></pre></div><hr><h2 id="_11-6-context-propagation-review-points" tabindex="-1">11.6 Context Propagation Review Points <a class="header-anchor" href="#_11-6-context-propagation-review-points" aria-label="Permalink to “11.6 Context Propagation Review Points”">​</a></h2><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Context propagation passes request context along the call chain.</span></span>
<span class="line"><span>Common Headers include X-Request-Id, X-User-Id, X-Tenant-Id, Authorization.</span></span>
<span class="line"><span>Gateway is responsible for generating or validating context.</span></span>
<span class="line"><span>Downstream services parse Headers via Filters.</span></span>
<span class="line"><span>Feign continues Header propagation via RequestInterceptor.</span></span>
<span class="line"><span>ThreadLocal must be cleared in a finally block.</span></span>
<span class="line"><span>Do not blindly trust user identity Headers from clients.</span></span></code></pre></div><hr><h2 id="_12-one-sentence-summary" tabindex="-1">12. One-Sentence Summary <a class="header-anchor" href="#_12-one-sentence-summary" aria-label="Permalink to “12. One-Sentence Summary”">​</a></h2><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Nacos solves where services are and where configurations are;</span></span>
<span class="line"><span>OpenFeign solves how to elegantly call between services;</span></span>
<span class="line"><span>Sentinel solves how to protect the system during high traffic or downstream failures;</span></span>
<span class="line"><span>Gateway solves unified entry, routing, filtering, authentication, and context propagation for microservices;</span></span>
<span class="line"><span>Full-link context propagation solves how to maintain consistent identity, tenant, and trace information across multiple services for a single request.</span></span></code></pre></div>`,21)])])}const u=s(t,[["render",l]]);export{g as __pageData,u as default};
